import React, { useEffect, useState } from 'react';
import ECGChart from './components/ECGChart';
import RiskHistory from './components/RiskHistory';
import StatsPanel from './components/StatsPanel';
import axios from 'axios';

// BACKEND URLs (CHANGE IP IF NEEDED)
const LIVE_ECG_URL = "http://192.168.0.10:5000/live_ecg";
const LATEST_RESULT_URL = "http://192.168.0.10:5000/latest_result";

export default function App() {
  const [processed, setProcessed] = useState(null);
  const [rawECG, setRawECG] = useState([]);
  const [analysis, setAnalysis] = useState(null);
  const [history, setHistory] = useState([]);

  // ============================================================
  // 🔥 1. FETCH LIVE ECG WAVEFORM (every 300ms)
  // ============================================================
  useEffect(() => {
    const id = setInterval(async () => {
      try {
        const res = await fetch(LIVE_ECG_URL);
        const json = await res.json();

        if (json.ecg && json.ecg.length > 0) {
          const formatted = json.ecg.map((v, i) => ({
            index: i,
            value: v
          }));

          setRawECG(formatted);
        }
      } catch (err) {
        console.log("ECG fetch error:", err);
      }
    }, 300);

    return () => clearInterval(id);
  }, []);

  // ============================================================
  // 🔥 2. FETCH LATEST ML ANALYSIS (every 1.5s)
  // ============================================================
  useEffect(() => {
    const id = setInterval(async () => {
      try {
        const res = await axios.get(LATEST_RESULT_URL);

        if (res.data) {
          setAnalysis(res.data);

          const r = res.data.rf_probabilities
            ? res.data.rf_probabilities[1] * 100
            : 0;

          setHistory(h => [
            ...h.slice(-59),
            { time: new Date().toLocaleTimeString(), risk: r }
          ]);
        }
      } catch (e) {
        console.log("Analysis fetch error:", e);
      }
    }, 1500);

    return () => clearInterval(id);
  }, []);


  // ============================================================
// 🔥 3. FETCH PROCESSED ECG SIGNALS (every 1.2s)
// ============================================================
useEffect(() => {
  const id = setInterval(async () => {
    try {
      const res = await axios.get("http://192.168.0.10:5000/processed_ecg");
      if (res.data) {
        setProcessed(res.data);
      }
    } catch (err) {
      console.log("Processed ECG fetch error:", err);
    }
  }, 1200);

  return () => clearInterval(id);
}, []);

  // ============================================================
  // 🔥 3. RENDER UI
  // ============================================================
  return (
    <div className="min-h-screen bg-gray-50 p-6 font-sans">
      <div className="max-w-6xl mx-auto">

        {/* HEADER */}
        <header className="flex items-center justify-between mb-6">
          <h1 className="text-3xl font-bold">ECG AI — Live Monitoring</h1>

          <div className="text-sm text-gray-600">
            Status:
            {rawECG.length > 0 ? (
              <span className="text-green-600 ml-1">Receiving ECG</span>
            ) : (
              <span className="text-red-600 ml-1">Waiting...</span>
            )}
          </div>
        </header>

        {/* GRID */}
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">

          {/* LIVE ECG */}
          <div className="lg:col-span-2 bg-white p-4 rounded shadow">
            <h2 className="text-xl font-semibold mb-2">Live ECG</h2>
            <ECGChart data={rawECG} />
          </div>

          {/* STATS */}
          <div className="bg-white p-4 rounded shadow">
            <StatsPanel analysis={analysis} />
          </div>
        </div>

        {/* RISK HISTORY */}
        <div className="mt-6 bg-white p-4 rounded shadow">
          <h3 className="text-lg font-semibold mb-2">Risk History</h3>
          <RiskHistory history={history} />
        </div>

      </div>
    </div>
  );
}
